}

import { useQuery, useAction, getTasks, createTask, updateTask } from 'wasp/client/operations'
import { logout } from 'wasp/client/auth'
import { FormEvent, useState } from 'react'
import { Task } from 'wasp/entities'

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskAction = useAction(createTask)
  const updateTaskAction = useAction(updateTask)

  const [description, setDescription] = useState('')

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault()
    try {
      await createTaskAction({ description })
      setDescription('')
    } catch (err: any) {
      window.alert('Error: ' + err.message)
    }
  }

  const handleToggle = async (id: number, isDone: boolean) => {
    try {
      await updateTaskAction({ id, isDone: !isDone })
    } catch (err: any) {
      window.alert('Error: ' + err.message)
    }
  }

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + (error as any).message

  return (
    <div style={{ maxWidth: '600px', margin: '0 auto', padding: '2rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1>Todo List</h1>
        <button onClick={logout}>Logout</button>
      </div>

      <form onSubmit={handleSubmit} style={{ marginBottom: '1rem' }}>
        <input
          type="text"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="New task"
          required
        />
        <button type="submit">Add Task</button>
      </form>

      {tasks && (tasks as Task[]).length === 0 && <p>No tasks yet.</p>}

      <ul>
        {tasks && (tasks as Task[]).map((task) => (
          <li key={task.id} style={{ listStyle: 'none', marginBottom: '0.5rem' }}>
            <input
              type="checkbox"
              checked={task.isDone}
              onChange={() => handleToggle(task.id, task.isDone)}
            />
            <span style={{ textDecoration: task.isDone ? 'line-through' : 'none', marginLeft: '0.5rem' }}>
              {task.description}
            </span>
          </li>
        ))}
      </ul>
    </div>
  )
}
